<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list :IsShowAction="true" :showCheckBox="false" ModuleName="Company" SubModuleCode="CompanyHoliday"
                IdentityColumn="holidayid" :HeaderText="$t('ContractHoliday')" :ListData="CompanyHolidayData" :HeaderData="Header"
                :TotalRecords="TotalRecords" :IsSearchFieldsOnTop="false" SearchPosition="top" :SearchFields="topSearchFields" 
                :RenderRowActionMethod="renderActions" :ListDataCallBackFunction="FetchData"
                :IsFilterApplied="searchCondition ? true : false" v-on:LeftsearchButtonClick="leftCommonSearch" :LegendArray="LegendArray" sourcetype=""
                v-on:PagerButtonClick="pagerMethod" v-on:HeaderButtonClick="commonHeaderButtonClick"
                v-on:ActionButtonClick="actionButtonClick" v-on:ClearFilter="ClearFilter" v-on:SortdataButtonClick="sortdata" :NorecordfoundText="$t('NoRecordfound')">           
                <template v-slot:slotdata="{ data }">
                    <template v-if="data.column.COLUMN_NAME == 'Duration'">                    
                        <span v-if="data.row.isfullday">{{ $t('FullDay') }}</span>
                        <span v-else>{{ $t('PartialDay') }}</span>
                    </template>
                    <template v-if="data.column.COLUMN_NAME == 'holidayname'">                
                        <span v-if="data.row.isManual && data.row.isEditEnable"><a href="javascript:;"  @click="EditContractHoliday(data.row)">{{ data.row.holidayname }}</a></span>
                        <span v-else>{{ data.row.holidayname }}</span>
                    </template>
                    <template v-if="data.column.COLUMN_NAME == 'holidaydate'"> 
                        <span>{{ $options.filters.formatDate(data.row.holidaydate)  }}</span>
                    </template>
                    <template v-if="data.column.COLUMN_NAME == 'Time'">                    
                        <span v-if="data.row.isfullday">{{ $t('NA') }}</span>
                        <span v-else>{{ FromTime(data.row.fromtime) }} To {{ FromTime(data.row.totime) }}</span>
                    </template>
                    <template v-if="data.column.COLUMN_NAME == 'AvailableIn'">                    
                        <span v-if="data.row.isForCompany">{{ $t('Company')}}</span><br>
                        <span v-if="data.row.isForContract">{{ $t('Client') }} </span>
                        <a v-if="data.row.isForContract" class="text-primary showContracts" @click="IsShowContractModal(data.row.holidayid)"><em class="fa fa-eye"></em></a> 
                    </template>
                    <template v-if="data.column.COLUMN_NAME == 'HolidayType'">                                     
                        <span v-if="data.row.isFixed">{{ $t('Fixed')}}</span>
                        <span v-else>{{ $t('Observed') }} </span> 
                    </template>
                    <template v-if="data.column.COLUMN_NAME == 'isrecurring'">                    
                        <span v-if="data.row.isrecurring">{{ $t('Yes')}}</span>
                        <span v-else>{{ $t('No') }} </span> 
                    </template>
                    <template v-if="data.column.COLUMN_NAME == 'companylocation'">
                        {{ formatCompanyLocation(data.row.companylocation) }}
                        </template>
                    <template v-if="data.column.COLUMN_NAME == 'statusid'">
                          <listing-status :isfor="'UpdateHolidayStatus'" 
                            ref="updatestatus" v-bind:dataid="data.row.holidayid" data-controller="Client"
                            v-bind:statuslist="StatusListForListing" v-bind:item="data.statusid" data-action="index"
                            v-bind:dataselected="data.row.statusid == 1001 ? 'Active' : 'Inactive'"
                            v-bind:callbackfunction="FetchData" v-bind:isselectedvaluestring="true">
                        </listing-status>                      
                    </template>
                </template>
            </tg-list>
            <AddContractHoliday v-if="IsAddContract" :IsFor="IsFor" :ContractHolidayData="ContractHolidayData" @CloseAddContract="CloseAddContract"></AddContractHoliday>
            <ContractViewHoliday v-if="IsContractHolidayModal" :ContractHolidayId="ContractHolidayId"></ContractViewHoliday>
        </section>
</template>
<script>
import Schema from './ContractHoliday';
import DataService from '../../../services/DataService';
import AddContractHoliday from './AddContractHoliday.vue';
import ContractViewHoliday from './ContractViewHoliday.vue';
export default {
    components:{AddContractHoliday,ContractViewHoliday},
    data(){
        return{
            isLoading:false,
            CompanyHolidayData:[],
            TotalRecords: 0,
             LegendArray: [{
                class: 'legends_medium colorboxsquare',
                text: this.$t('HolidayBank')
            }, {
                class: 'legend-pending colorboxsquare',
                text:this.$t(`ManualHoliday`)
            }],
            StatusListForListing: [{ STATUS: 'Active', STATUS_ID: 1001, STATUS_COLOR: "#ffffff", STATUS_BG_COLOR: "#28a745" },
            { STATUS: 'Inactive', STATUS_ID: 1002, STATUS_COLOR: "#ffffff", STATUS_BG_COLOR: "#d72435" }],
            PageSize: 10,
            PageNumber: 1,
            isPaged: 1,
            TotalPages: 0,
            noRecord:false,
            SortBy: '',
            SortExp: '',
            topSearchFields: Schema.topsearchSchema,
            listActions: Schema.listActions,
            Header:[
                {
                    "COLUMN_NAME": "holidayname",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "name",
                    "DISPLAY_ORDER": 1,
                    settings : {
                        isInSlot: true
                    }             
                },
                {
                    "COLUMN_NAME": "holidaydate",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Date",
                    "DISPLAY_ORDER": 1,
                    settings : {
                        isInSlot: true
                    }                
                },
                {
                    "COLUMN_NAME": "holidaydescription",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "DESCRIPTION",
                    "DISPLAY_ORDER": 1                
                },
                {
                    "COLUMN_NAME": "Duration",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Duration",
                    "DISPLAY_ORDER": 1,
                    settings : {
                        isInSlot: true
                    }              
                },
                {
                    "COLUMN_NAME": "Time",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Time",
                    "DISPLAY_ORDER": 1,
                    settings : {
                        isInSlot: true
                    }                 
                },
                {
                    "COLUMN_NAME": "AvailableIn",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "AvailableIn",
                    "DISPLAY_ORDER": 1,
                    settings : {
                        isInSlot: true
                    }               
                },
                {
                    "COLUMN_NAME": "HolidayType",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "HolidayType",
                    "DISPLAY_ORDER": 1,
                    settings : {
                        isInSlot: true
                    }                
                },
                {
                    "COLUMN_NAME": "isrecurring",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Recurring",
                    "DISPLAY_ORDER": 1,
                    settings : {
                        isInSlot: true
                    }               
                },
                {
                    "COLUMN_NAME": "companylocation",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Locations",
                    "DISPLAY_ORDER": 1,
                    settings : {
                        isInSlot: true
                    }                
                },
                {
                    "COLUMN_NAME": "statusid",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Status",
                    "DISPLAY_ORDER": 1,
                    settings : {
                        isInSlot: true
                    }               
                },
            ],
            ContractHolidayData:null,
            IsAddContract:false,
            UserId:0,
            ContractHolidayId:0,
            IsContractHolidayModal:false,
            IsFor:'',
            searchCondition:''
        }
    },
    created:async function(){
        var ths= this;
        var UserDateFormat= ths.GetUserInfo.DateFormat == ""? 'MM/DD/YYYY' : ths.GetUserInfo.DateFormat;
        ths.UserId=ths.$route.params.id;
        Schema.bindleftCommonSearchdropdown(ths, "Company", "Location");
        if (ths.topSearchFields?.length > 0) {
            ths.topSearchFields.find(f => f.fieldName === 'DateRange').format= UserDateFormat;
            ths.topSearchFields.find(f => f.fieldName === 'DateRange').onChange= ths.setTimerDate;
        }
        await ths.FetchData();
        
    },
    methods:{
         setTimerDate(x) {
            this.applySecondDate(x);
        },
          applySecondDate(x) {
    // allow all dates
    x.datePickerConfig.maxDate = '';
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const formatDate = (d) => {
        const mm = String(d.getMonth() + 1).padStart(2, '0');
        const dd = String(d.getDate()).padStart(2, '0');
        const yyyy = d.getFullYear();
        return `${mm}/${dd}/${yyyy}`;
    };

    const parseDate = (val) => {
        if (val instanceof Date && !isNaN(val.getTime())) {
            const d = new Date(val);
            d.setHours(0, 0, 0, 0);
            return d;
        }

        if (typeof val === 'string' && val) {
            const parts = val.split(/[\/\-]/);
            if (parts.length === 3) {
                const month = parseInt(parts[0], 10) - 1;
                const day   = parseInt(parts[1], 10);
                const year  = parseInt(parts[2], 10);

                const d = new Date(year, month, day);
                d.setHours(0, 0, 0, 0);
                return isNaN(d.getTime()) ? null : d;
            }
        }
        return null;
    };

    /* 🔑 NEW RULE: keep future secondValue if already present */
    const secondValueDate = parseDate(x.secondValue);
    if (secondValueDate) {
        x.secondValue = formatDate(secondValueDate);
        return;
    }

    /* Existing logic */
    const valueDate = parseDate(x.value);

    if (valueDate && valueDate > today) {
        x.secondValue = formatDate(valueDate);
    } else {
        x.secondValue = formatDate(today);
    }
},
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },
        ClearFilter(){

        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case 'EditContractHoliday':
                    this.EditContractHoliday(item)
                    break;
                case 'DeleteContractHoliday':
                    this.DeleteContractHoliday(item);
                    break; 
                case 'CloneContractHoliday':
                    this.CloneContractHoliday(item);
                    break; 
            }
        },
        commonHeaderButtonClick(){},
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
          leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            debugger
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    this.searchCondition = value.searchConditionJson;
                } else {
                    this.searchCondition = value.searchCondition || "";

                }
            } else {
                this.searchCondition = "";
            }
             if (this.searchCondition) {
                this.searchCondition = this.searchCondition.replace(/DateRange=([^&]+)/, function (_, val) {
                    let [from, to] = val.split("|");
                    if (from && !to) {
                        to = new Date().toISOString().split('T')[0];
                    }
                    return `dateFrom=${from}&dateTo=${to}`;
                });
            }
            this.FetchData();
        },
         formatCompanyLocation(locations) {
            if (!locations) return '--';

            return locations
            .split(',')
            .map(x => x.trim())
            .filter(Boolean)
            .join(', ');
        },
        async FetchData(){ 
            var vueObj=this;
            vueObj.isLoading=true;
            var url=`statusIds=&duration=&sortBy=${vueObj.SortBy}&sortExp=${vueObj.SortExp}&pageSize=${vueObj.PageSize}&pageNum=${vueObj.PageNumber}&clientId=${vueObj.UserId}&contractId`
            if (vueObj.searchCondition) {
                url += `&${vueObj.searchCondition}`;
            };         
            await DataService.CompanyHolidayList(url).then((response)=>{ 
                vueObj.isLoading=false; 
                if(response.data.length>0){                    
                    vueObj.CompanyHolidayData=response.data;   
                    vueObj.CompanyHolidayData.forEach(item => {
                                item.additionalClass = '';
                                if (item.isManual ==false && item.holiday_Bank_Id>0) {
                                    item.additionalClass='medium-bar';
                                }else{
                                    item.additionalClass='high-bar';
                                }
                              
                    });               
                    vueObj.TotalRecords = vueObj.CompanyHolidayData[0].totaL_RECORDS;
                    vueObj.TotalPages = Math.ceil(vueObj.TotalRecords / vueObj.PageSize);
                    vueObj.noRecord = false;
                }else{
                    vueObj.CompanyHolidayData = [];
                    vueObj.noRecord = true;
                    vueObj.TotalRecords = 0
                }
            })
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'Delete':
                        action.isVisible = true;
                        break;
                    case 'Edit':
                        action.isDisabled = (row.isEditEnable && row.isManual)==true ?false: true;
                        action.isVisible = true;
                        break;
                    case 'Clone':
                        action.isVisible = (row.isEditEnable && row.isManual)==true ?true:false;
                        break;
                    
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        EditContractHoliday(itm){
            var vm =this;            
            vm.IsFor='Update';
            vm.ContractHolidayData=itm;
            vm.IsAddContract=true;
        },
        CloseAddContract(){
            var vm =this;
            vm.IsAddContract=false; 
            vm.FetchData();
        },
        DeleteContractHoliday(itm){
            var ths=this;
            ths.isLoading=true;
            var reqForm=ths.UserId != null?"ContractHoliday": "CompanyHoliday";
            var url=`id=${itm.holidayid}&reqFrom=${reqForm}&refId=${ths.UserId}`;
            DataService.DeleteContractHoliday(url).then((response)=>{
                if(response.data.msg=='success'){
                    ths.ShowAlert(ths.$t('SuccessfullyDelete',[ths.$t('ContractHoliday')]),"success", true, ths.$t("Alert"));
                    ths.FetchData();
                }else{
                    ths.ShowAlert(ths.$t('ErrorWhileProcessingRequest'),"failure", true, ths.$t("Alert"));
                }
                ths.isLoading=false;
            })
        },
        FromTime(val){
            var date = new Date(val);          
            var hours = date.getHours();
            var minutes = date.getMinutes();   
            var period = hours >= 12 ? 'PM' : 'AM';
            var hours12 = hours % 12;  
            hours12 = hours12 ? hours12 : 12; 
            minutes = minutes < 10 ? '0' + minutes : minutes;
            var timeWithAMPM = `${hours12}:${minutes}:${period}`;
            return timeWithAMPM;
        },
        IsShowContractModal(val){
            var ths = this;
            ths.ContractHolidayId=val;
            ths.IsContractHolidayModal=true;
        },
        CloneContractHoliday(itm){
            var ths =this;
            ths.IsFor='Clone';
            itm.holidayid=0;            
            ths.ContractHolidayData=itm;
            ths.IsAddContract=true;
        }
    }
}
</script>